code.JavaScript:
function generateParenthesis(n) {
    const result = [];
    function backtrack(open, close, str) {
        if (open === n && close === n) {
            result.push(str);
            return;
        }
        if (open < n) {
            backtrack(open + 1, close, str + "(");
        }
        if (close < open) {
            backtrack(open, close + 1, str + ")");
        }
    }
    backtrack(0, 0, "");
    return result;
}
